#include <unordered_set>

class Solution {
public:
    int longestPalindrome(string s, string t) {
        unordered_set<string> seen;
        int max_len = 0;
        for (int i = 0; i < s.length(); i++) {
            string prefix = s.substr(0, i);
            string suffix = t.substr(0, i);
            if (seen.find(prefix + suffix) != seen.end() && seen[prefix + suffix].length() > max_len) {
                max_len = seen[prefix + suffix].length();
            }
            seen.insert(prefix + suffix);
        }
        return max_len;
    }
};
